import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const AdminDashboard = () => {
  const { user, token } = useAuth();
  const navigate = useNavigate();
  const [salesData, setSalesData] = useState(null);
  const [mlData, setMlData] = useState(null);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    if (user?.role !== 'admin') {
      navigate('/');
      return;
    }
    fetchData();
  }, [user, navigate, token]);

  const fetchData = async () => {
    try {
      const [salesRes, predictionRes, chartRes, usersRes] = await Promise.all([
        axios.get('http://localhost:5000/api/admin/sales-report', {
          headers: { Authorization: `Bearer ${token}` }
        }),
        axios.get('http://localhost:8000/api/sales-prediction'),
        axios.get('http://localhost:8000/api/sales-chart'),
        axios.get('http://localhost:5000/api/admin/users', {
          headers: { Authorization: `Bearer ${token}` }
        })
      ]);
      
      setSalesData(salesRes.data);
      setMlData({
        prediction: predictionRes.data,
        chart: chartRes.data
      });
      setUsers(usersRes.data);
    } catch (error) {
      console.error('Failed to fetch data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!user || user.role !== 'admin') {
    return <div>Access denied. Admin only.</div>;
  }

  if (loading) {
    return <div>Loading dashboard...</div>;
  }

  return (
    <div className="admin-dashboard">
      <h1>Admin Dashboard</h1>
      
      <div className="dashboard-tabs">
        <button 
          className={activeTab === 'overview' ? 'active' : ''}
          onClick={() => setActiveTab('overview')}
        >
          Overview
        </button>
        <button 
          className={activeTab === 'users' ? 'active' : ''}
          onClick={() => setActiveTab('users')}
        >
          Users & Orders
        </button>
      </div>

      {activeTab === 'overview' && (
        <div>
          <div className="sales-summary">
            <div className="summary-card">
              <h3>Total Sales</h3>
              <p className="summary-value">₹{Math.round((salesData?.totalSales || 0) * 83)}</p>
            </div>
            <div className="summary-card">
              <h3>Total Orders</h3>
              <p className="summary-value">{salesData?.totalOrders || 0}</p>
            </div>
            {mlData?.prediction && (
              <div className="summary-card">
                <h3>Next Month Prediction</h3>
                <p className="summary-value">₹{Math.round(mlData.prediction.prediction * 83)}</p>
                <small className={`trend ${mlData.prediction.trend}`}>
                  {mlData.prediction.trend} ({mlData.prediction.growth_rate?.toFixed(1)}%)
                </small>
              </div>
            )}
          </div>

          {mlData?.chart && (
            <div className="ml-charts">
              <h2>Sales Analytics</h2>
              <div className="chart-container">
                <img src={mlData.chart.chart} alt="Sales Trend" className="sales-chart" />
              </div>
            </div>
          )}

          <div className="sales-report">
            <h2>Sales Report</h2>
            <table className="sales-table">
              <thead>
                <tr>
                  <th>Product Name</th>
                  <th>Quantity Sold</th>
                  <th>Amount</th>
                </tr>
              </thead>
              <tbody>
                {salesData?.productSales?.map((product, index) => (
                  <tr key={index}>
                    <td>{product.name}</td>
                    <td>{product.quantity}</td>
                    <td>₹{Math.round(product.amount * 83)}</td>
                  </tr>
                )) || <tr><td colSpan="3">No sales data</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'users' && (
        <div className="users-list">
          <h2>Users & Their Orders</h2>
          {users.map(user => (
            <div key={user._id} className="user-card">
              <div className="user-header">
                <h3>{user.name}</h3>
                <div className="user-stats">
                  <span className="stat">Orders: {user.totalOrders}</span>
                  <span className="stat">Spent: ₹{Math.round(user.totalSpent * 83)}</span>
                </div>
              </div>
              
              <div className="user-details">
                <p><strong>Email:</strong> {user.email}</p>
                <p><strong>Joined:</strong> {new Date(user.createdAt).toLocaleDateString()}</p>
              </div>

              {user.orders.length > 0 && (
                <div className="user-orders">
                  <h4>Recent Orders:</h4>
                  {user.orders.slice(0, 3).map(order => (
                    <div key={order._id} className="order-summary">
                      <div className="order-info">
                        <span className="order-id">#{order._id.slice(-8)}</span>
                        <span className="order-amount">₹{Math.round(order.totalAmount * 83)}</span>
                        <span className={`order-status ${order.orderStatus.toLowerCase()}`}>
                          {order.orderStatus}
                        </span>
                      </div>
                      <div className="order-date">
                        {new Date(order.orderDate).toLocaleDateString()}
                      </div>
                    </div>
                  ))}
                  {user.orders.length > 3 && (
                    <p className="more-orders">+{user.orders.length - 3} more orders</p>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
